import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Оновлення Fabric на Linux","description":"Покрокова інструкція щодо оновлення Fabric на Linux.","frontmatter":{"title":"Оновлення Fabric на Linux","description":"Покрокова інструкція щодо оновлення Fabric на Linux.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"uk_ua/players/updating-fabric/linux.md","filePath":"translated/uk_ua/players/updating-fabric/linux.md","lastUpdated":1774518827000}`);var s={name:`uk_ua/players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Оновлення Fabric на Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Оновлення Fabric на Linux”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Завантаження встановлювача Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Завантаження встановлювача Fabric”">​</a></h2><p>Завантажте версію <code>.jar</code> встановлювача Fabric з <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сайту Fabric</a>, натиснувши <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запустіть встановлювач Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запустіть встановлювач Fabric”">​</a></h2><p>Перш ніж запустити встановлювач, закрийте Minecraft та запускач Minecraft.</p><p>Відкрийте термінал і запустіть установлювач за допомогою Java:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Коли ви відкриєте встановлювач, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установлювач Fabric із виділеним «Установити»" loading="lazy"></p><p>Переконайтеся, що нова версія гри та Завантажувача правильні, а потім натисніть «Установити», щоб оновити Fabric.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Під час запуску встановлювача обов’язково приберіть вибір «Створити інсталяцію»!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Оновіть інсталяцію у запускачі Minecraft <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Оновіть інсталяцію у запускачі Minecraft”">​</a></h2><p>Після завершення встановлення відкрийте запускач Minecraft. Потім перейдіть на вкладку <code>Інсталяції</code>. Знайдіть свою інсталяцію Fabric і відкрийте її екран редагування:</p><p><img src="/assets/players/updating-fabric.png" alt="Оновлення версії Завантажувача Fabric у запускачі Minecraft" loading="lazy"></p><p>Замініть версію новою версією Завантажувача Fabric, яку ви щойно встановили, і натисніть <code>Зберегти</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. Усе готово! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Усе готово!”">​</a></h2><p>Виконавши кроки, ви можете повернутися на вкладку <code>Грати</code>, вибрати інсталяцію Fabric зі спадного меню в нижньому лівому куті та натиснути кнопку «Грати»!</p><p>Якщо під час виконання цієї інструкції у вас виникнуть проблеми, ви можете звернутися за допомогою в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord Fabric</a> в каналі <code>#player-support</code>.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};